/**
 * Minimal logger utility.
 * In production, consider using a structured logger like pino or winston.
 */
import { config } from "./config.js";

const levels = ["debug", "info", "warn", "error"];
const currentLevelIdx = levels.indexOf(config.logging.level);

function logAt(level, ...args) {
  const idx = levels.indexOf(level);
  if (idx >= currentLevelIdx) {
    const ts = new Date().toISOString();
    // eslint-disable-next-line no-console
    console[level === "debug" ? "log" : level](`[${ts}] [${level.toUpperCase()}]`, ...args);
  }
}

export const logger = {
  debug: (...args) => logAt("debug", ...args),
  info: (...args) => logAt("info", ...args),
  warn: (...args) => logAt("warn", ...args),
  error: (...args) => logAt("error", ...args)
};

