/**
 * Minimal CLI parser (no external deps). Supports:
 *  --key=value or --key value
 */
function parseCliArgs(argv) {
  const args = {};
  for (let i = 2; i < argv.length; i++) {
    const cur = argv[i];
    if (cur.startsWith("--")) {
      const [k, v] = cur.split("=");
      const key = k.replace(/^--/, "");
      if (v !== undefined) {
        args[key] = v;
      } else {
        // Value may be in next token
        const next = argv[i + 1];
        if (next && !next.startsWith("--")) {
          args[key] = next;
          i++;
        } else {
          args[key] = true;
        }
      }
    }
  }
  return args;
}

